   1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
   2→import { Circle, Group, Image as KonvaImage, Layer, Line, Rect, Text } from "react-konva";
   3→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
   4→import { addCanvasMargin, addCanvasStamp, deleteCanvasMargin, deleteCanvasStamp, getCanvasMargins, getCanvasStamps } from "../../../../API/Api";
   5→import { useAuth } from "../../../Context/useAuth";
   6→import supabase from "../../../utils/supabaseClient";
   7→import { parseCanvasDoc } from "../../../utils/canvasDoc";
   8→import CanvasSurface, { buildSortedCanvasObjects, getCanvasStageHeight } from "./CanvasSurface";
   9→import styles from "./CanvasEditor.module.css";
  10→import "./canvas.css";
  11→
  12→const STAMP_ICONS = {
  13→    heart: "❤️",
  14→    star: "⭐",
  15→    question: "❓",
  16→    fire: "🔥"
  17→};
  18→
  19→const CANVAS_MAX_WIDTH = 560;
  20→const MOBILE_BREAKPOINT = 820;
  21→const CANVAS_ROOT_SNIPPET_ID = "canvas-root";
  22→const STAMP_SIZE = 34;
  23→const STAMP_FONT_SIZE = 30;
  24→const PROFILE_SIZE = 13;
  25→const STICKY_WIDTH = 172;
  26→const STICKY_HEIGHT = 118;
  27→const REALTIME_CHANNEL_SUFFIX_LENGTH = 8;
  28→const OPTIMISTIC_STAMP_PREFIX = "optimistic-stamp";
  29→const OPTIMISTIC_MARGIN_PREFIX = "optimistic-margin";
  30→const DOODLE_COLOR_PRESETS = [
  31→    "#5f92ff",
  32→    "#ff4d6d",
  33→    "#ff7f11",
  34→    "#ffd23f",
  35→    "#22c55e",
  36→    "#14b8a6",
  37→    "#8b5cf6",
  38→    "#111827",
  39→    "#ffffff"
  40→];
  41→const LIVE_DOODLE_BROADCAST_EVENT = "doodle-progress";
  42→const LIVE_DOODLE_END_EVENT = "doodle-end";
  43→const LIVE_DOODLE_BROADCAST_INTERVAL_MS = 40;
  44→const LIVE_DOODLE_STALE_MS = 2200;
  45→
  46→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  47→const createOptimisticId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  48→const toTimestamp = (value) => {
  49→    const parsed = Date.parse(value || "");
  50→    return Number.isNaN(parsed) ? 0 : parsed;
  51→};
  52→const sortByCreatedAt = (a, b) => {
  53→    const byDate = toTimestamp(a?.created_at) - toTimestamp(b?.created_at);
  54→    if(byDate !== 0){
  55→        return byDate;
  56→    }
  57→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  58→};
  59→const sanitizeNormalizedPoints = (rawPoints) => {
  60→    if(!Array.isArray(rawPoints)){
  61→        return [];
  62→    }
  63→
  64→    const numericPoints = rawPoints
  65→        .map((point) => Number(point))
  66→        .filter((point) => !Number.isNaN(point))
  67→        .map((point) => clamp(point, 0, 1));
  68→
  69→    if(numericPoints.length < 2){
  70→        return [];
  71→    }
  72→
  73→    return numericPoints.length % 2 === 0
  74→        ? numericPoints
  75→        : numericPoints.slice(0, -1);
  76→};
  77→const getNameInitial = (name) => {
  78→    const normalizedName = typeof name === "string" ? name.trim() : "";
  79→    return normalizedName ? normalizedName.slice(0, 1).toUpperCase() : "?";
  80→};
  81→
  82→const useLoadedImage = (src) => {
  83→    const [image, setImage] = useState(null);
  84→
  85→    useEffect(() => {
  86→        if(!src){
  87→            setImage(null);
  88→            return;
  89→        }
  90→
  91→        const img = new window.Image();
  92→        img.crossOrigin = "anonymous";
  93→        img.onload = () => setImage(img);
  94→        img.onerror = () => setImage(null);
  95→        img.src = src;
  96→
  97→        return () => {
  98→            img.onload = null;
  99→            img.onerror = null;
 100→        };
 101→    }, [src]);
 102→
 103→    return image;
 104→};
 105→
 106→const emojiCanvasCache = new Map();
 107→
 108→const useEmojiImage = (emoji, size) => {
 109→    const [image, setImage] = useState(null);
 110→
 111→    useEffect(() => {
 112→        if(!emoji){
 113→            setImage(null);
 114→            return;
 115→        }
 116→
 117→        const cacheKey = `${emoji}_${size}`;
 118→        if(emojiCanvasCache.has(cacheKey)){
 119→            setImage(emojiCanvasCache.get(cacheKey));
 120→            return;
 121→        }
 122→
 123→        const canvas = document.createElement("canvas");
 124→        const scale = window.devicePixelRatio || 1;
 125→        canvas.width = size * scale;
 126→        canvas.height = size * scale;
 127→        const ctx = canvas.getContext("2d");
 128→        ctx.scale(scale, scale);
 129→        ctx.textAlign = "center";
 130→        ctx.textBaseline = "middle";
 131→        ctx.font = `${size * 0.82}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", "Android Emoji", sans-serif`;
 132→        ctx.fillText(emoji, size / 2, size / 2);
 133→
 134→        const img = new window.Image();
 135→        img.onload = () => {
 136→            emojiCanvasCache.set(cacheKey, img);
 137→            setImage(img);
 138→        };
 139→        img.src = canvas.toDataURL();
 140→    }, [emoji, size]);
 141→
 142→    return image;
 143→};
