 255→const CanvasViewer = ({journalId, canvasDoc, authorId}) => {
 256→    const {session, user, openAuthModal} = useAuth();
 257→    const queryClient = useQueryClient();
 258→    const shellRef = useRef(null);
 259→    const stageRef = useRef(null);
 260→    const viewerClientIdRef = useRef(createOptimisticId("canvas-client"));
 261→    const realtimeChannelRef = useRef(null);
 262→    const currentDoodlePointsRef = useRef([]);
 263→    const pendingDoodlePayloadRef = useRef(null);
 264→    const doodleBroadcastTimerRef = useRef(null);
 265→    const lastDoodleBroadcastAtRef = useRef(0);
 266→
 267→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 268→    const [activeStampType, setActiveStampType] = useState("heart");
 269→    const [activeTool, setActiveTool] = useState("stamp");
 270→    const [draggingStampType, setDraggingStampType] = useState("");
 271→    const [isDropActive, setIsDropActive] = useState(false);
 272→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 273→    const [doodleSize, setDoodleSize] = useState(2.8);
 274→    const [isDrawing, setIsDrawing] = useState(false);
 275→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 276→    const [liveDoodlesByClient, setLiveDoodlesByClient] = useState({});
 277→    const [isMobileViewport, setIsMobileViewport] = useState(false);
 278→    const [isMobileDockOpen, setIsMobileDockOpen] = useState(false);
 279→
 280→    const parsedCanvasDoc = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
 281→    const sortedObjects = useMemo(
 282→        () => buildSortedCanvasObjects(parsedCanvasDoc?.snippets || [], parsedCanvasDoc?.images || []),
 283→        [parsedCanvasDoc?.images, parsedCanvasDoc?.snippets]
 284→    );
 285→
 286→    useEffect(() => {
 287→        const getContentWidth = () => {
 288→            const el = shellRef.current;
 289→            if(!el){
 290→                return CANVAS_MAX_WIDTH;
 291→            }
 292→            const style = getComputedStyle(el);
 293→            const paddingLeft = parseFloat(style.paddingLeft) || 0;
 294→            const paddingRight = parseFloat(style.paddingRight) || 0;
 295→            return el.clientWidth - paddingLeft - paddingRight;
 296→        };
 297→
 298→        const updateShellWidth = () => {
 299→            setShellWidth(getContentWidth());
 300→        };
 301→
 302→        updateShellWidth();
 303→        window.addEventListener("resize", updateShellWidth);
 304→
 305→        let resizeObserver = null;
 306→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 307→            resizeObserver = new ResizeObserver(updateShellWidth);
 308→            resizeObserver.observe(shellRef.current);
 309→        }
 310→
 311→        return () => {
 312→            window.removeEventListener("resize", updateShellWidth);
 313→            if(resizeObserver){
 314→                resizeObserver.disconnect();
 315→            }
 316→        };
 317→    }, []);
 318→
 319→    useEffect(() => {
 320→        const mediaQuery = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
 321→        const syncViewport = () => setIsMobileViewport(mediaQuery.matches);
 322→        syncViewport();
 323→
 324→        if(typeof mediaQuery.addEventListener === "function"){
 325→            mediaQuery.addEventListener("change", syncViewport);
 326→            return () => mediaQuery.removeEventListener("change", syncViewport);
 327→        }
 328→
 329→        mediaQuery.addListener(syncViewport);
 330→        return () => mediaQuery.removeListener(syncViewport);
 331→    }, []);
 332→
 333→    useEffect(() => {
 334→        if(isMobileViewport){
 335→            setIsMobileDockOpen(false);
 336→            return;
 337→        }
 338→        setIsMobileDockOpen(true);
 339→    }, [isMobileViewport]);
 340→
 341→    const stageWidth = useMemo(() => Math.max(240, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 342→    const stageHeight = getCanvasStageHeight(stageWidth, parsedCanvasDoc?.meta?.aspectRatio);
 343→    const doodleStrokeScale = useMemo(() => clamp(stageWidth / CANVAS_MAX_WIDTH, 0.45, 1), [stageWidth]);
 344→    const stampScale = useMemo(() => clamp(stageWidth / CANVAS_MAX_WIDTH, 0.6, 1), [stageWidth]);
 345→    const stickyScale = useMemo(() => clamp(stageWidth / CANVAS_MAX_WIDTH, 0.62, 1), [stageWidth]);
 346→    const stickyWidth = useMemo(() => Math.max(116, Math.round(STICKY_WIDTH * stickyScale)), [stickyScale]);
 347→    const stickyHeight = useMemo(() => Math.max(82, Math.round(STICKY_HEIGHT * stickyScale)), [stickyScale]);
 348→    const stickyPadding = useMemo(() => Math.max(7, Math.round(10 * stickyScale)), [stickyScale]);
 349→    const stickyFontSize = useMemo(() => Math.max(12, Number((15 * stickyScale).toFixed(2))), [stickyScale]);
 350→    const stickyCornerRadius = useMemo(() => Math.max(6, Number((8 * stickyScale).toFixed(2))), [stickyScale]);
 351→    const stickyShadowBlur = useMemo(() => Math.max(4, Number((8 * stickyScale).toFixed(2))), [stickyScale]);
 352→    const stickyShadowOffsetY = useMemo(() => Math.max(2, Number((3 * stickyScale).toFixed(2))), [stickyScale]);
 353→
 354→    const {data: stampData} = useQuery({
 355→        queryKey: ["canvasStamps", journalId],
 356→        queryFn: () => getCanvasStamps(journalId, session?.access_token),
 357→        enabled: !!journalId,
 358→        refetchOnWindowFocus: false
 359→    });
 360→
 361→    const {data: marginData} = useQuery({
 362→        queryKey: ["canvasMargins", journalId],
 363→        queryFn: () => getCanvasMargins(journalId, session?.access_token),
 364→        enabled: !!journalId,
 365→        refetchOnWindowFocus: false
 366→    });
 367→
 368→    const stampsQueryKey = useMemo(() => ["canvasStamps", journalId], [journalId]);
 369→    const marginsQueryKey = useMemo(() => ["canvasMargins", journalId], [journalId]);
 370→    const currentUserProfile = user?.userData?.[0] || null;
 371→    const currentUserId = currentUserProfile?.id || null;
 372→    const canUseDoodle = Boolean(currentUserId && String(currentUserId) === String(authorId));
 373→
 374→    useEffect(() => {
 375→        if(!canUseDoodle && activeTool === "doodle"){
 376→            setActiveTool("stamp");
 377→            setIsDrawing(false);
 378→            setCurrentDoodlePoints([]);
 379→            currentDoodlePointsRef.current = [];
 380→        }
 381→    }, [activeTool, canUseDoodle]);
 382→
 383→    const getKnownUserProfile = useCallback((targetUserId) => {
 384→        if(!targetUserId){
 385→            return {user_name: null, user_image_url: null};
 386→        }
 387→
 388→        if(currentUserProfile?.id === targetUserId){
 389→            return {
 390→                user_name: currentUserProfile?.name || null,
 391→                user_image_url: currentUserProfile?.image_url || null
 392→            };
 393→        }
 394→
 395→        const knownStamps = queryClient.getQueryData(stampsQueryKey)?.stamps || [];
 396→        const knownMargins = queryClient.getQueryData(marginsQueryKey)?.items || [];
 397→        const match = [...knownStamps, ...knownMargins].find((item) => (
 398→            item?.user_id === targetUserId && (item?.user_name || item?.user_image_url)
 399→        ));
 400→
 401→        return {
 402→            user_name: match?.user_name || null,
 403→            user_image_url: match?.user_image_url || null
 404→        };
 405→    }, [currentUserProfile?.id, currentUserProfile?.image_url, currentUserProfile?.name, marginsQueryKey, queryClient, stampsQueryKey]);
 406→
 407→    const normalizeStampRow = useCallback((row) => {
 408→        if(!row?.id){
 409→            return null;
 410→        }
 411→        const knownProfile = getKnownUserProfile(row.user_id);
 412→        return {
 413→            id: row.id,
 414→            journal_id: row.journal_id,
 415→            user_id: row.user_id,
 416→            snippet_id: row.snippet_id,
 417→            word_key: row.word_key,
 418→            stamp_type: row.stamp_type,
 419→            x: row.x,
 420→            y: row.y,
 421→            created_at: row.created_at,
 422→            user_name: row.user_name ?? knownProfile.user_name ?? null,
 423→            user_image_url: row.user_image_url ?? knownProfile.user_image_url ?? null
 424→        };
 425→    }, [getKnownUserProfile]);
 426→
 427→    const normalizeMarginRow = useCallback((row) => {
 428→        if(!row?.id){
 429→            return null;
 430→        }
 431→        const knownProfile = getKnownUserProfile(row.user_id);
 432→        return {
 433→            id: row.id,
 434→            journal_id: row.journal_id,
 435→            user_id: row.user_id,
 436→            item_type: row.item_type,
 437→            payload: row.payload || null,
 438→            created_at: row.created_at,
 439→            updated_at: row.updated_at,
 440→            user_name: row.user_name ?? knownProfile.user_name ?? null,
 441→            user_image_url: row.user_image_url ?? knownProfile.user_image_url ?? null
 442→        };
 443→    }, [getKnownUserProfile]);
 444→
 445→    const upsertStampCache = useCallback((stamp) => {
 446→        if(!stamp?.id){
 447→            return;
 448→        }
 449→
 450→        queryClient.setQueryData(stampsQueryKey, (old) => {
 451→            const previous = Array.isArray(old?.stamps) ? old.stamps : [];
 452→            const existingIndex = previous.findIndex((item) => String(item?.id) === String(stamp.id));
 453→            let nextStamps = previous;
 454→
 455→            if(existingIndex === -1){
 456→                nextStamps = [...previous, stamp];
 457→            } else {
 458→                nextStamps = [...previous];
 459→                nextStamps[existingIndex] = {...nextStamps[existingIndex], ...stamp};
 460→            }
 461→
 462→            nextStamps.sort(sortByCreatedAt);
 463→            return {...(old || {}), stamps: nextStamps};
 464→        });
 465→    }, [queryClient, stampsQueryKey]);
 466→
 467→    const upsertMarginCache = useCallback((item) => {
 468→        if(!item?.id){
 469→            return;
 470→        }
 471→
 472→        queryClient.setQueryData(marginsQueryKey, (old) => {
 473→            const previous = Array.isArray(old?.items) ? old.items : [];
 474→            const existingIndex = previous.findIndex((entry) => String(entry?.id) === String(item.id));
 475→            let nextItems = previous;
 476→
 477→            if(existingIndex === -1){
 478→                nextItems = [...previous, item];
 479→            } else {
 480→                nextItems = [...previous];
 481→                nextItems[existingIndex] = {...nextItems[existingIndex], ...item};
 482→            }
 483→
 484→            nextItems.sort(sortByCreatedAt);
 485→            return {...(old || {}), items: nextItems};
 486→        });
 487→    }, [marginsQueryKey, queryClient]);
 488→
 489→    const removeStampFromCache = useCallback((stampId) => {
 490→        if(!stampId){
 491→            return null;
 492→        }
 493→
 494→        let removedStamp = null;
 495→        queryClient.setQueryData(stampsQueryKey, (old) => {
 496→            const previous = Array.isArray(old?.stamps) ? old.stamps : [];
 497→            removedStamp = previous.find((item) => String(item?.id) === String(stampId)) || null;
 498→            const nextStamps = previous.filter((item) => String(item?.id) !== String(stampId));
 499→            return {...(old || {}), stamps: nextStamps};
 500→        });
 501→        return removedStamp;
 502→    }, [queryClient, stampsQueryKey]);
 503→
 504→    const removeMarginFromCache = useCallback((marginId) => {
 505→        if(!marginId){
 506→            return null;
 507→        }
 508→
 509→        let removedItem = null;
 510→        queryClient.setQueryData(marginsQueryKey, (old) => {
 511→            const previous = Array.isArray(old?.items) ? old.items : [];
 512→            removedItem = previous.find((entry) => String(entry?.id) === String(marginId)) || null;
 513→            const nextItems = previous.filter((entry) => String(entry?.id) !== String(marginId));
 514→            return {...(old || {}), items: nextItems};
 515→        });
 516→        return removedItem;
 517→    }, [marginsQueryKey, queryClient]);
 518→
 519→    const eventBelongsToJournal = useCallback((payload) => {
 520→        const journalIdAsString = String(journalId);
 521→        const newJournalId = payload?.new?.journal_id;
 522→        const oldJournalId = payload?.old?.journal_id;
 523→
 524→        if(newJournalId !== undefined){
 525→            return String(newJournalId) === journalIdAsString;
 526→        }
 527→        if(oldJournalId !== undefined){
 528→            return String(oldJournalId) === journalIdAsString;
 529→        }
 530→        return null;
 531→    }, [journalId]);
 532→
 533→    const clearQueuedDoodleBroadcast = useCallback(() => {
 534→        if(doodleBroadcastTimerRef.current){
 535→            clearTimeout(doodleBroadcastTimerRef.current);
 536→            doodleBroadcastTimerRef.current = null;
 537→        }
 538→    }, []);
 539→
 540→    const sendBroadcastEvent = useCallback((eventName, payload) => {
 541→        const channel = realtimeChannelRef.current;
 542→        if(!channel){
 543→            return;
 544→        }
 545→
 546→        channel.send({
 547→            type: "broadcast",
 548→            event: eventName,
 549→            payload: payload
 550→        }).catch((error) => {
 551→            console.error("Failed to send canvas broadcast event:", error);
 552→        });
 553→    }, []);
 554→
 555→    const flushQueuedDoodleBroadcast = useCallback(() => {
 556→        if(!pendingDoodlePayloadRef.current){
 557→            return;
 558→        }
 559→
 560→        const nextPayload = pendingDoodlePayloadRef.current;
 561→        pendingDoodlePayloadRef.current = null;
 562→        lastDoodleBroadcastAtRef.current = Date.now();
 563→        sendBroadcastEvent(LIVE_DOODLE_BROADCAST_EVENT, nextPayload);
 564→    }, [sendBroadcastEvent]);
 565→
 566→    const queueDoodleBroadcast = useCallback((payload, immediate = false) => {
 567→        pendingDoodlePayloadRef.current = payload;
 568→        if(immediate){
 569→            clearQueuedDoodleBroadcast();
 570→            flushQueuedDoodleBroadcast();
 571→            return;
 572→        }
 573→
 574→        const elapsed = Date.now() - lastDoodleBroadcastAtRef.current;
 575→        const delay = Math.max(0, LIVE_DOODLE_BROADCAST_INTERVAL_MS - elapsed);
 576→        if(doodleBroadcastTimerRef.current){
 577→            return;
 578→        }
