 259→router.get('/getNotifications', requireAuth, async(req, res) =>{
 260→    const {before, limit} = req.query;
 261→    const userId = req.userId;
 262→
 263→    // Fetch a generous amount from both tables, then merge and paginate
 264→    const fetchLimit = parseInt(limit) + 1;
 265→
 266→    let journalQuery = supabase
 267→    .from('notifications')
 268→    .select(
 269→        `*,
 270→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 271→        users!sender_id(name, user_email, image_url, id, badge),
 272→        constellation_id,
 273→        constellations!constellation_id(status, star_id_a, star_id_b)
 274→        `
 275→    )
 276→    .eq('receiver_id', userId)
 277→    .order('created_at', {ascending: false})
 278→    .order('id', {ascending: false})
 279→    .limit(fetchLimit)
 280→
 281→    let opinionQuery = supabase
 282→    .from('notification_opinions')
 283→    .select(
 284→        `*,
 285→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 286→        users!sender_id(name, user_email, image_url, id, badge)
 287→        `
 288→    )
 289→    .eq('receiver_id', userId)
 290→    .order('created_at', {ascending: false})
 291→    .order('id', {ascending: false})
 292→    .limit(fetchLimit)
 293→
 294→    if(before){
 295→        journalQuery = journalQuery.lt('created_at', before);
 296→        opinionQuery = opinionQuery.lt('created_at', before);
 297→    }
 298→
 299→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 300→
 301→    if(journalResult.error){
 302→        console.error('error while fetching data from notification table:', journalResult.error);
 303→        return res.status(500).json({error: 'error fetching data from notification table'});
 304→    }
 305→    if(opinionResult.error){
 306→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 307→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 308→    }
 309→
 310→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 311→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 312→
 313→    // Merge and sort by created_at descending
 314→    const merged = [...journalNotifs, ...opinionNotifs]
 315→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 316→
 317→    // Likes/bookmarks lookup only for journal notifications
 318→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 319→
 320→    let hasLikedResult = [];
 321→    let hasBookMarkedResult = [];
 322→    if(journalIds.length > 0){
 323→        const [hasLiked, hasBookMarked] = await Promise.all([
 324→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 325→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 326→        ]);
 327→
 328→        if(hasLiked.error || hasBookMarked.error){
 329→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 330→        }
 331→        hasLikedResult = hasLiked.data || [];
 332→        hasBookMarkedResult = hasBookMarked.data || [];
 333→    }
 334→
 335→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 336→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 337→
 338→    const formatted = merged.map((notif) => ({
 339→        ...notif,
 340→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 341→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 342→    }))
 343→
 344→    const hasMore = formatted.length > parseInt(limit);
 345→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 346→
 347→    return res.status(200).json(
 348→        {
 349→            hasMore: hasMore,
 350→            data: slicedData,
 351→        }
